var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거긴 어때? 뭐 찾은 거 있어?","JPN":"どう？　何か目ぼしいものはあった？","ENG":"How's it looking over there? Did you find anything?","TWN":"那邊怎麼樣？有找到什麼嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_SNOW"},{"id":"L3_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"아뇨. 적철도, 사람 흔적도 발견하지 못했습니다.","JPN":"いいえ、赤鉄も、人の痕跡も見当たりませんでした。","ENG":"No. No signs of Violarite or humans.","TWN":"沒有，連個人影也沒看見，更不用說赤鐵。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이곳이 도시였다는 걸 증명하는 건 우리가 밟고 다니는 지붕이 전부입니다.","JPN":"ここがかつて都市だったという証拠となるのは、私たちが踏んでいる屋根しかありません。","ENG":"The roofs we are currently walking on are the only evidence that this was once a city.","TWN":"能證明這裡曾經是城市的，只有我們腳下踩的這些屋頂。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어쩌면 20년동안 내린 눈 때문에 아래에 전부 묻혔을지도 모르지요.","JPN":"もしかすると、20年も降り続けた雪のせいで、なにもかもが埋もれてしまっているのかもしれません。","ENG":"Perhaps everything is buried underneath after twenty years of snow.","TWN":"或許是20年來不斷地積雪，東西可能都埋在這底下。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇, 그럼 이 넓은 곳을 어디서부터 파헤쳐야 하는 거지?","JPN":"ちっ、こんなに広大な場所、どこから掘り起こせばいいのよ。","ENG":"Tch. Then where are we supposed to start digging in this large area?","TWN":"嘖，這麼大的地方，是要從哪裡開始挖起？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기, 모르가나…","JPN":"あの、モルガナ……","ENG":"Um, Morgana...","TWN":"那個，莫甘娜…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"무슨 일이야? 황소허벅지.","JPN":"どうしたの？　大根足。","ENG":"What is it, thick thighs?","TWN":"什麼事，蜜大腿？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아하하…","JPN":"あはは……","ENG":"Ah hah hah...","TWN":"哈哈…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"20년 전의 조사단 사람들은 동토에 내리는 눈이 녹지도 그치지도 않는단 걸 알고 있었겠죠?","JPN":"20年前に来た調査団の方々は凍土の雪は解けることも降り止むこともないことは知っていましたよね？","ENG":"The survey corps from twenty years ago was also aware that the snow in the gelid lands doesn't melt or stop falling, right?","TWN":"20年前的調查員應該都知道這裡的雪既不會融化，也不會停止吧？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그야 당연하잖아. 그 정도는 그루터기의 꼬맹이들도 아는 사실이라고.","JPN":"当たり前でしょ。そんなこと切り株のガキたちだって知っているわよ。","ENG":"Of course. Even the kids at the Stump know that.","TWN":"那當然，這種事連木墩的小孩子都知道。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"만약 그런 분들이 훗날 저희가 올 걸 대비해 뭔가를 남겼다면…","JPN":"もしかしたらその方たちは、私たちがここに来ることを予想して、何かを残していたとしたら……","ENG":"Then, if they left something in anticipation that we'd come for them one day...","TWN":"那些人若是要為將來的我們留下些什麼資訊…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아마도 눈이 쌓이지 않을 가장 높은 장소를 고르지 않았을까… 라는 생각이 들어서요.","JPN":"おそらく雪が積もることのない、一番高い場所を選んだんじゃないかなって……思いつきまして。","ENG":"I think they would've picked the highest location... where snow wouldn't pile up.","TWN":"應該會選擇留在一個不會積雪的至高點吧…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"좋아. 확인해보자.","JPN":"よし、調べてみよう。","ENG":"Okay. Let's go check it out.","TWN":"好，去確認一下吧。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"여깁니다! 이 첨탑이 일대에서 가장 높은 건축물이예요.","JPN":"ここです！　この尖塔がこの一帯では一番高い建物になります。","ENG":"Over here! The spire is the tallest structure here.","TWN":"就是這裡！這座尖塔是這一帶最高的建築物。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이건 등대잖아?","JPN":"これは灯台じゃない！？","ENG":"This is a lighthouse, isn't it?","TWN":"這是燈塔吧？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"등대가 뭐죠?","JPN":"灯台って何ですか？","ENG":"What's a lighthouse?","TWN":"什麼是燈塔？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어둠 속에서 배가 길을 잃지 않게 해주는 탑이야. 바다와 맞닿은 도시엔 적어도 하나씩 있지.","JPN":"暗い中でも船が進行方向を見失わないようにしてくれる塔のことよ。港町には必ずあるの。","ENG":"It's a tower that prevents boats from getting lost in the dark. There is at least one in every city facing the sea.","TWN":"就是讓在黑暗中航行的船隻不至於迷路的高塔，每個靠海的城市都至少會有一座。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 전에도 이런 걸 본 적이 있어요?","JPN":"モルガナは以前にも同じものを見たことがあるんですか？","ENG":"Have you ever seen one before, Morgana?","TWN":"莫甘娜，這你以前見過嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"본 적은 없지만 배웠어.","JPN":"見たことはないけれど、習ったのよ。","ENG":"I haven't, but I learned about it.","TWN":"沒親眼見過，但在課本上學過。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린 같은 드루이드가 되려면 아발론의 역사를 비롯해 많은 지식을 알고 있어야 하니까.","JPN":"マーリンのようなドロイドになるためには、アバロンの歴史を含め、様々な知識に精通していなければならないから。","ENG":"I need to be knowledgeable in Avalon's history if I want to become a Druid like Merlin.","TWN":"要成為像梅林那樣的德魯伊，從阿瓦隆的歷史，到其他相關的知識都必須知道。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 지식이 당장은 별 쓸모없을 것 같아도… 결국엔 다 쓸모가 있거든.","JPN":"その知識がすぐに使えるものではなくても……いつか役に立つときが来るからね。","ENG":"Even if it doesn't seem useful at the time... they all have some use in the end.","TWN":"就算當下可能無法學以致用…但終究會派上用場的。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"등대의 입구가 보이지 않는군요. 눈 아래에 파묻혀버린 모양입니다.","JPN":"灯台の入口が見当たりませんね。雪に埋もれてしまったんでしょう。","ENG":"I can't find the entrance to the lighthouse. It seems to be buried in the snow.","TWN":"看不到燈塔的入口，似乎是被埋在積雪底下。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"꼭대기만 확인해볼 수 있으면 좋겠지만, 저길 무슨 수로 올라가죠?","JPN":"天辺だけでも確認したいのですが、あんなところまでどうやって登りましょうか？","ENG":"It would be best to just check the top, but how do we get up there?","TWN":"真想去塔頂看看，但是要怎麼上去呢…？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇… 미끄러워서 벽을 타기도 쉽지 않겠네.","JPN":"ちっ……滑りやすくて壁面を登るのも難しそうね。","ENG":"Tch... I guess climbing the wall won't be easy because it's so slippery.","TWN":"嘖…塔面這麼滑也不太好爬。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"한 번 던져보는 건 어떨까요?","JPN":"投げてみるというのはどうですか？","ENG":"How about throwing?","TWN":"還是試試看把誰扔上去？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"던진다고? 뭘?","JPN":"投げる？　何を？","ENG":"Throw? Like what?","TWN":"用扔的？要扔誰？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야? 왜 날 빤히 쳐다보는데?","JPN":"何よ、何であたしをじっと見るのよ？","ENG":"Huh? Why are you looking at me?","TWN":"幹嘛？為什麼看我？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"설마… 날 던지겠단 거야?","JPN":"もしかして……あたしを投げるつもり？","ENG":"You... want to throw me?","TWN":"難道…你是想把我扔上去？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저 이래봬도 성자라서 힘은 세거든요.","JPN":"こう見えて、私も聖者なので力はあるんです。","ENG":"I am a Helgon, so strength isn't a problem.","TWN":"你別看我這樣，我好歹也是聖者，力氣很大的。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 가벼우니까, 한 번 해볼만하지 않을까요?","JPN":"モルガナは軽いので、一度やってみましょうか？","ENG":"And you're light, so it's worth a shot.","TWN":"你那麼輕，試試看應該沒關係吧？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…알겠어.","JPN":"……わかったわ。","ENG":"...Fine.","TWN":"…好吧。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"저 꼭대기까지 가려면 그 방법이 제일 빠르겠네.","JPN":"天辺まで行くには、その方法が最も手っ取り早いわね。","ENG":"I guess it's the fastest way to reach the top.","TWN":"誰叫這是去塔頂最快的方法。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼, 던질게요!","JPN":"では、投げますよ！","ENG":"Okay, I'm going to throw you!","TWN":"那，我要扔囉！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"응…?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯…？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자, 잠깐만…! 으핫!","JPN":"ちょ、ちょっと待って……！！　ふあっ！","ENG":"W-wait...! Whoa!","TWN":"欸，等等…？嚇哈！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"蛤？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"꺄하하하하핫!","JPN":"キャハハハハッ！　","ENG":"KYAAAAAAH!","TWN":"哈哈哈哈哈！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아학, 아학, 아하하하하!!","JPN":"ウハ、ウハ、ウハハハハハッ！","ENG":"Ah hah hah hah hah!!!","TWN":"哈哈，哈哈，哈哈哈哈哈！！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나…?","JPN":"モルガナ……？","ENG":"Morgana...?","TWN":"莫甘娜…？"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"갑자기 왜 그래요? 무섭게.","JPN":"いきなりどうしたんですか？","ENG":"What's wrong? You're scaring me.","TWN":"你幹嘛？怎麼突然笑得那麼恐怖？"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아학- 헥-","JPN":"はあ、ヘッ、ヘッ！","ENG":"Ah hah... haa...","TWN":"哈——哈——"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"후아아…","JPN":"ふぅぅ……","ENG":"Whew...","TWN":"呼呼呼…"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너야 말로 뭐하는 짓이야! 갑자기 겨드랑이에 손을 끼우면 어떡해!","JPN":"あなたこそ何すんのよ！　いきなり脇に手を入れたらくすぐったいでしょ！","ENG":"What are you doing?! Why did you suddenly put your hands in my armpits?!","TWN":"我才要問你咧！沒事把伸到人家腋下幹嘛！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네? 그야 모르가나를 던지려면 우선 들어야 하니까…","JPN":"はい？　投げるには、そうするしかないじゃないですか……","ENG":"Huh? Well, I have to lift you up first if I'm going to throw you...","TWN":"蛤？不把你舉起來是要怎麼扔…"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"시끄러!","JPN":"うるさい！","ENG":"Shut it!","TWN":"閉嘴！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"절대로! 다시는!","JPN":"もう二度と！　絶対に！","ENG":"Never! Again!","TWN":"我不准！聽到沒有！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내 겨드랑이에 손대지 마! 알아들어?!","JPN":"あたしの脇に触らないでよ！　いい！？","ENG":"Don't you dare touch my armpits! You got that?!","TWN":"不許再碰我的腋下！知道嗎？！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네에…","JPN":"はぁい……","ENG":"Okay...","TWN":"喔喔…"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"모르가나 아가씨는 다른 사람의 손길에 무척 예민합니다.","JPN":"モルガナお嬢様は他人に触られることに、異常に敏感なんです。","ENG":"Miss Morgana is sensitive to other people touching her.","TWN":"小姐很敏感，不習慣別人碰她。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어릴 적 사냥놀이를 하다 구덩이에 몸이 끼었을 때도, 멀린 님의 도움을 받다가 혼절할 정도였으니까요.","JPN":"幼い頃、狩人ごっこをしていて、堀に身体がハマってしまい、マーリン様に助けてもらったときも、気絶したぐらいですからね。","ENG":"Even when she was young and got stuck in a hole while playing hunting, she almost fainted while Merlin tried to help her.","TWN":"小時候有一次玩躲貓貓，她不小心掉到坑裡，梅林祭司長救她出來的時候，她還暈了過去呢。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거, 거기서 갑자기 옛날 얘긴 할 필요 없잖아.","JPN":"き、急に昔の話はしなくてもいいでしょ。","ENG":"Y-you don't have to bring up the past all of a sudden.","TWN":"你…你幹嘛突然提起過去的事啦！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나에게 그런 약점이 있었다니.","JPN":"モルガナにそんな弱点があったなんて。","ENG":"I didn't know Morgana had a weakness.","TWN":"原來莫甘娜還有這樣的弱點。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"기억해둬야겠네요.","JPN":"覚えておかないとですね。","ENG":"I should keep note of it.","TWN":"我要記下來。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그거, 앞으로 조심하겠다는 뜻 맞지?","JPN":"それは、今後気をつけるっていう意味よね？","ENG":"You mean you're going to be careful about it from now on, right?","TWN":"記下來的意思是，你之後會留意吧？！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내 손깍지에 발 올려. 내가 던져줄 테니까.","JPN":"あたしの手の上に乗って。あたしが投げてあげるから。","ENG":"Place your foot on my palms. I'll throw you like this.","TWN":"…換你把腳踩在我的手掌上，我來把你拋出去。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"괜찮나요? 저 모르가나만큼 가볍지 않은데.","JPN":"大丈夫なんですか？　私はモルガナほど軽くはありませんよ。","ENG":"You sure? But I'm not as light as you, Morgana.","TWN":"確定嗎？我不像你那麼輕喔。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"누굴 걱정하는 거야? 난 곰도 던져버릴 수 있다고.","JPN":"誰の心配をしているの？　あたしはクマでもぶん投げれるのよ。","ENG":"Who are you worried about? I'm strong enough to even toss a bear.","TWN":"擔心什麼？我連熊都舉得起來。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"고, 곰이라뇨! 그 정도로 무겁진 않다구요!","JPN":"く、クマですか！　私はそこまで重くはないですから！","ENG":"A b-bear?! I'm not that heavy!","TWN":"你說誰是熊！我才沒那麼重咧！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아무튼 간다!","JPN":"いいから、投げるわよ！","ENG":"Anyway, up you go!","TWN":"總之來吧！"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"흐앗?! 보통 셋 세고 던지는 거 아닌가요?","JPN":"ふぇっ！　普通は3つ数えてから投げるものですよね？","ENG":"Huah?! Don't people normally count to three before throwing?","TWN":"啊？！不是應該數到三再扔嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"한 번에 무사히 들어갔군요.","JPN":"一発で無事成功しましたね。","ENG":"A hole in one.","TWN":"一下就飛上去咧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어때? 시신이라거나, 뭔가 눈에 띄는 거 있어?","JPN":"どう？　遺体とか、何か見つかった？","ENG":"What do you see? Is there anything out of the ordinary, like a corpse or something?","TWN":"怎麼樣？有沒有發現屍體或其他東西？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아뇨, 시신은 없지만… 신기한 물건을 찾았어요.","JPN":"いいえ、遺体はないのですが……変わったモノがありました。","ENG":"No, no corpses, but... I did find something interesting.","TWN":"沒有屍體…但我找到一個奇妙的東西。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모래가 담긴 병인데 구리로 만들었나봐요.","JPN":"砂の入った瓶で、鉛で作られているようです。","ENG":"It's a copper bottle that's filled with sand.","TWN":"是一個裝滿沙子的瓶子，瓶子好像是銅做的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아마도 향로일 거야.","JPN":"おそらく香炉ね。","ENG":"That's probably an incense burner.","TWN":"可能是香爐吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"종교적인 의식을 할 때 연기를 피우는 용도지.","JPN":"宗教的な儀式を行うときに使う、煙を出すための道具よ。","ENG":"It's used in religious ceremonies to create smoke.","TWN":"在某些宗教儀式中會拿來燒香的東西。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼 두 손을 모으고 있는 이 커다란 조각상은요?","JPN":"じゃあ、この両手を合わせている大きな彫象は？","ENG":"Then, what about the huge statue with its hands clasped?","TWN":"那這個雙手合十的大型雕像呢？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"몰라. 아마 이 지방 사람들이 숭배하던 신 같은 거겠지.","JPN":"それは知らない。この地方の人たちが崇拝する神の類じゃないかしら。","ENG":"I don't know. Maybe some god the people here worshipped.","TWN":"不知道，可能是這個地方的人崇拜的神祇。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아발론이 분열된 뒤에 세워진 문명들은, 저마다 다른 형태의 신앙을 가졌다고 배웠으니까.","JPN":"アバロンから分裂して発生した文明は、それぞれ違う形の信仰を持つようになったと習ったわ。","ENG":"I was taught that the civilizations that came after Avalon's division each had their own faith.","TWN":"課本上說，在阿瓦隆分裂後，各個文明各自形成不同的信仰。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그런 거 말고 좀 더 눈에 띄는 수상한 흔적 없어?","JPN":"そういうのじゃなくて、もっと手がかりになりそうなものはない？","ENG":"Other than that, is there anything suspicious that catches your eye?","TWN":"還有沒有其他可疑的地方？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"수상한 흔적이라…","JPN":"手がかりになりそうなもの……","ENG":"Something suspicious...","TWN":"可疑的地方…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"喔。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"벽면에 글씨가 쓰여져 있어요.","JPN":"壁に文字が書かれています。","ENG":"There are a few writings on the wall.","TWN":"牆上有字！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이거… 피로 새긴 것 같은데요?","JPN":"これは……血で書かれているようですね？","ENG":"I think... it's written in blood?","TWN":"好像…是用血寫的？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"피로 된 글씨? 뭐라고 적혀 있는데?","JPN":"血で書かれた文字？　なんて書いてあるの？","ENG":"Writings in blood? What does it say?","TWN":"用血寫的字？上面寫什麼？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"<color=#ff3636>종이 울리면… 악마가 온다.</color>","JPN":"<color=#ff3636>鐘が鳴れば……悪魔がやってくる。</color>","ENG":"<color=#ff3636>The devil will come... when the bell rings.</color>","TWN":"<color=#ff3636>鐘聲響起之時…便是惡魔降臨之時。</color>"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이 소리는…?","JPN":"この音は……！？","ENG":"What's that sound...?","TWN":"有聲音…？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"아, 아가씨!","JPN":"お、お嬢様！","ENG":"M-Miss Morgana!","TWN":"小…小姐！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"능선에 누군가 있습니다!","JPN":"山稜に何者かがいます！","ENG":"There is someone on the ridge!","TWN":"山脊上好像有人！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL4"},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야 저건…? 허수아비?","JPN":"あれは……？　カカシ？","ENG":"What is that...? A scarecrow?","TWN":"那是什麼…？稻草人？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"대체 언제부터 우릴 보고 있던 거지?","JPN":"いったいいつからこちらの様子をうかがっていたんだろう？","ENG":"Since when has it been looking at us?","TWN":"它是從什麼時候開始盯上我們的？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"아가씨! 반대편에도 비슷하게 생긴 놈들이 나타났습니다!","JPN":"お嬢様！　反対側にも似た姿のやつらが現れました！","ENG":"Miss Morgana! There are more of them on the other side too!","TWN":"小姐！對面也有出現類似的傢伙！"},"stage":{"bg":"SNOWYARD_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"한 둘이 아닙니다! 숫자가 점점 늘고 있어요!","JPN":"一、二体じゃありません！　どんどん増えてきています！","ENG":"And it's more than just a couple of them! They're growing in numbers!","TWN":"不止一、二個！數量有增加的趨勢！"},"stage":{"bg":"SNOWYARD_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇, 우리가 포위당했다고?","JPN":"ちっ、取り囲まれちゃったわけね。","ENG":"Tch, they've surrounded us?","TWN":"嘖，我們被包圍了嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"포위가 아직 완벽하진 않아요! 제가 시선을 끌 테니 반대로 달리세요!","JPN":"完全に囲まれたわけじゃありません！　私が注意を引きますので、逆方向に逃走してください！","ENG":"But they haven't surrounded us completely! I'll distract them, so run to the other side!","TWN":"還沒完全被包圍！我來吸引它們的注意力，你們往反方向跑！"},"stage":{"bg":"SKY","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐? 그럼 넌 어쩌고?","JPN":"えっ？　あなたはどうするの？","ENG":"What? Then what about me?","TWN":"什麼？那你怎麼辦？"},"stage":{"bg":"SKY","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"시간이 없으니 어서요!","JPN":"時間がないですから、早く！","ENG":"There's no time! Hurry!","TWN":"沒時間了，快！"},"stage":{"bg":"SKY","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"다들 능선 아래로 달려! 저것들을 따돌려야 해!","JPN":"みんな、山稜の下を走って！　あいつらを振り切るよ！","ENG":"Everyone, run down the ridge! We must lose them!","TWN":"大家跑到山脊下！甩掉它們！"},"stage":{"bg":"SNOWYARD_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};